/**
 * Stripe Webhook Handler
 *
 * POST /api/webhooks/stripe
 *
 * Verifies Stripe webhook signature, updates Transaction status, and grants
 * entitlements on successful payment. Always returns 200 to satisfy Stripe's
 * requirement for fast acknowledgment.
 *
 * @fileType api-route
 * @domain payments
 * @pattern webhook
 * @ai-summary Handles Stripe webhook events for payment confirmation and refunds
 */

import { NextRequest, NextResponse } from 'next/server'
import Stripe from 'stripe'

import { getPayload } from 'payload'
import config from '@payload-config'

import { grantProductEntitlements } from '@/lib/payment/grant-entitlements'
import { verifyStripeWebhook } from '@/lib/payment/stripe'

export async function POST(request: NextRequest) {
  const payload = await getPayload({ config })

  // 1. Extract raw body as Buffer for signature verification
  const arrayBuffer = await request.arrayBuffer()
  const rawBody = Buffer.from(arrayBuffer)

  // 2. Extract signature header
  const signature = request.headers.get('stripe-signature')
  if (!signature) {
    payload.logger.error('Missing stripe-signature header')
    return NextResponse.json({ received: true }, { status: 200 })
  }

  // 3. Verify webhook signature
  let event: Stripe.Event
  try {
    event = await verifyStripeWebhook(rawBody, signature)
  } catch (err) {
    payload.logger.error({ error: err }, 'Stripe webhook signature verification failed')
    return NextResponse.json({ received: true }, { status: 200 })
  }

  // 4. Route event by type
  try {
    await handleEvent(payload, event)
  } catch (err) {
    payload.logger.error({ error: err, eventType: event.type }, 'Stripe webhook handler error')
  }

  return NextResponse.json({ received: true }, { status: 200 })
}

async function handleEvent(
  payload: Awaited<ReturnType<typeof getPayload>>,
  event: Stripe.Event,
): Promise<void> {
  switch (event.type) {
    case 'checkout.session.completed': {
      const sessionId = event.data.object.id

      // Find the transaction by providerTransactionId (Stripe session ID)
      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: sessionId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn({ sessionId }, 'Stripe webhook: transaction not found')
        return
      }

      const transaction = transactions.docs[0]

      // Idempotency: skip if already succeeded
      if (transaction.status === 'succeeded') {
        return
      }

      // Update status to succeeded
      await payload.update({
        collection: 'transactions',
        id: transaction.id,
        data: { status: 'succeeded' },
        overrideAccess: true,
      })

      // Grant entitlements
      try {
        await grantProductEntitlements(
          transaction.user as string,
          transaction.product as string,
          transaction.id,
        )
      } catch (err) {
        payload.logger.error(
          { error: err, transactionId: transaction.id },
          'Failed to grant product entitlements',
        )
      }
      break
    }

    case 'checkout.session.expired': {
      const sessionId = event.data.object.id

      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: sessionId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn(
          { sessionId },
          'Stripe webhook: transaction not found for session.expired',
        )
        return
      }

      await payload.update({
        collection: 'transactions',
        id: transactions.docs[0].id,
        data: { status: 'failed' },
        overrideAccess: true,
      })
      break
    }

    case 'charge.refunded': {
      const paymentIntentId = event.data.object.payment_intent as string

      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: paymentIntentId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn(
          { paymentIntentId },
          'Stripe webhook: transaction not found for charge.refunded',
        )
        return
      }

      await payload.update({
        collection: 'transactions',
        id: transactions.docs[0].id,
        data: { status: 'refunded' },
        overrideAccess: true,
      })
      break
    }

    default:
      // Unhandled event type — acknowledge without processing
      break
  }
}

/**
 * PayPal Webhook Handler
 *
 * POST /api/webhooks/paypal
 *
 * Verifies PayPal webhook signature, updates Transaction status, and grants
 * entitlements on successful payment. Always returns 200 to satisfy PayPal's
 * requirement for fast acknowledgment.
 *
 * @fileType api-route
 * @domain payments
 * @pattern webhook
 * @ai-summary Handles PayPal webhook events for payment confirmation and refunds
 */

import { NextRequest, NextResponse } from 'next/server'

import { getPayload } from 'payload'
import config from '@payload-config'

import { grantProductEntitlements } from '@/lib/payment/grant-entitlements'
import { verifyPayPalWebhook } from '@/lib/payment/paypal'

interface PayPalWebhookResource {
  id: string
  supplementary_data?: {
    related_ids?: {
      order_id?: string
    }
  }
}

interface PayPalWebhookEvent {
  event_type: string
  resource: PayPalWebhookResource
}

export async function POST(request: NextRequest) {
  const payload = await getPayload({ config })

  // 1. Parse body as JSON
  let body: object
  try {
    body = await request.json()
  } catch {
    payload.logger.error('Failed to parse PayPal webhook body')
    return NextResponse.json({ received: true }, { status: 200 })
  }

  // 2. Extract PayPal headers for signature verification
  const headers: Record<string, string> = {
    'paypal-transmission-id': request.headers.get('paypal-transmission-id') || '',
    'paypal-transmission-time': request.headers.get('paypal-transmission-time') || '',
    'paypal-transmission-sig': request.headers.get('paypal-transmission-sig') || '',
    'paypal-cert-url': request.headers.get('paypal-cert-url') || '',
    'paypal-auth-algo': request.headers.get('paypal-auth-algo') || '',
  }

  // 3. Verify webhook signature
  try {
    const isValid = await verifyPayPalWebhook(body, headers)
    if (!isValid) {
      payload.logger.error('PayPal webhook signature verification failed')
      return NextResponse.json({ received: true }, { status: 200 })
    }
  } catch (err) {
    payload.logger.error({ error: err }, 'PayPal webhook signature verification error')
    return NextResponse.json({ received: true }, { status: 200 })
  }

  // 4. Route event by type
  const event = body as PayPalWebhookEvent
  try {
    await handleEvent(payload, event)
  } catch (err) {
    payload.logger.error(
      { error: err, eventType: event.event_type },
      'PayPal webhook handler error',
    )
  }

  return NextResponse.json({ received: true }, { status: 200 })
}

async function handleEvent(
  payload: Awaited<ReturnType<typeof getPayload>>,
  event: PayPalWebhookEvent,
): Promise<void> {
  switch (event.event_type) {
    case 'CHECKOUT.ORDER.APPROVED': {
      const orderId = event.resource.id

      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: orderId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn({ orderId }, 'PayPal webhook: transaction not found')
        return
      }

      const transaction = transactions.docs[0]

      // Idempotency: skip if already succeeded
      if (transaction.status === 'succeeded') {
        return
      }

      // Update status to succeeded
      await payload.update({
        collection: 'transactions',
        id: transaction.id,
        data: { status: 'succeeded' },
        overrideAccess: true,
      })

      // Grant entitlements
      try {
        await grantProductEntitlements(
          transaction.user as string,
          transaction.product as string,
          transaction.id,
        )
      } catch (err) {
        payload.logger.error(
          { error: err, transactionId: transaction.id },
          'Failed to grant product entitlements',
        )
      }
      break
    }

    case 'PAYMENT.CAPTURE.COMPLETED': {
      // The capture ID is in resource.id, but we need the order ID to find the transaction.
      // Try to get the order ID from supplementary_data.related_ids.order_id
      const orderId = event.resource.supplementary_data?.related_ids?.order_id || event.resource.id

      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: orderId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn(
          { orderId },
          'PayPal webhook: transaction not found for PAYMENT.CAPTURE.COMPLETED',
        )
        return
      }

      const transaction = transactions.docs[0]

      // Idempotency guard: only process if still pending (skip if already succeeded, refunded, or failed)
      if (transaction.status !== 'pending') {
        return
      }

      await payload.update({
        collection: 'transactions',
        id: transaction.id,
        data: { status: 'succeeded' },
        overrideAccess: true,
      })
      break
    }

    case 'PAYMENT.CAPTURE.REFUNDED': {
      const captureId = event.resource.id

      const transactions = await payload.find({
        collection: 'transactions',
        where: {
          providerTransactionId: { equals: captureId },
        },
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      if (transactions.totalDocs === 0) {
        payload.logger.warn(
          { captureId },
          'PayPal webhook: transaction not found for PAYMENT.CAPTURE.REFUNDED',
        )
        return
      }

      await payload.update({
        collection: 'transactions',
        id: transactions.docs[0].id,
        data: { status: 'refunded' },
        overrideAccess: true,
      })
      break
    }

    default:
      // Unhandled event type — acknowledge without processing
      break
  }
}

/**
 * Transaction Refund Endpoint
 *
 * POST /api/admin/transactions/{id}/refund
 * Admin-only — calls refundStripe or refundPayPal and updates status to 'refunded'
 *
 * @fileType api-route
 * @domain payments
 */

import { NextRequest, NextResponse } from 'next/server'
import { getPayload } from 'payload'

import config from '@payload-config'
import type { Transaction } from '@/payload-types'
import { refundStripe } from '@/lib/payment/stripe'
import { refundPayPal } from '@/lib/payment/paypal'
import { AccountRole } from '@/server/payload/collections/Users/roles'

interface RouteParams {
  params: Promise<{ id: string }>
}

export async function POST(req: NextRequest, { params }: RouteParams) {
  const { id } = await params
  const payload = await getPayload({ config })

  // 1. Authenticate
  const authResult = await payload.auth({ headers: req.headers })
  if (!authResult.user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  // 2. Check admin role
  if (
    !('collection' in authResult.user) ||
    authResult.user.collection !== 'users' ||
    authResult.user.role !== AccountRole.Admin
  ) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 })
  }

  // 3. Fetch transaction
  let transaction: Transaction | null = null
  try {
    transaction = (await payload.findByID({
      collection: 'transactions',
      id,
      depth: 0,
      overrideAccess: true,
    })) as Transaction
  } catch (err) {
    // Handle both operational errors and not-found errors
    if (err instanceof Error && (err.name === 'NotFound' || err.message.includes('Not Found'))) {
      return NextResponse.json({ error: 'Transaction not found' }, { status: 404 })
    }
    throw err
  }

  if (!transaction) {
    return NextResponse.json({ error: 'Transaction not found' }, { status: 404 })
  }

  // 4. Validate status — double-refund guard
  if (transaction.status === 'refunded') {
    return NextResponse.json({ error: 'העסקה כבר הוחזרה' }, { status: 400 })
  }

  if (transaction.status !== 'succeeded') {
    return NextResponse.json(
      { error: 'Only succeeded transactions can be refunded' },
      { status: 400 },
    )
  }

  // 5. Call provider refund
  const { provider, providerTransactionId, amount } = transaction as {
    provider: 'stripe' | 'paypal'
    providerTransactionId: string
    amount: number
  }

  try {
    if (provider === 'stripe') {
      await refundStripe(providerTransactionId, amount)
    } else if (provider === 'paypal') {
      await refundPayPal(providerTransactionId, amount)
    } else {
      return NextResponse.json({ error: 'Unknown payment provider' }, { status: 400 })
    }
  } catch (err) {
    payload.logger.error({ error: err, transactionId: id, provider }, 'Refund operation failed')
    return NextResponse.json({ error: 'Refund operation failed' }, { status: 500 })
  }

  // 6. Update status to refunded
  await payload.update({
    collection: 'transactions',
    id,
    data: { status: 'refunded' },
    overrideAccess: true,
  })

  return NextResponse.json({ success: true })
}

